// Load saved theme on page load
if (localStorage.getItem('theme') === 'dark-grey') {
    document.body.classList.add('dark-grey-theme');
}

// GitHub data (fetched from local JSON generated by GitHub Action)
const GITHUB_DATA_URL = 'assets/github-data.json';

// Validate URL to prevent XSS (only allow https: scheme)
function safeUrl(url) {
    try {
        const parsed = new URL(url, window.location.href);
        return parsed.protocol === 'https:' ? url : null;
    } catch {
        return null;
    }
}

// Build modal content programmatically to avoid innerHTML XSS
function buildModalLink(container, href, text = 'Go') {
    const br = document.createElement('br');
    const link = document.createElement('a');
    link.href = href;
    link.textContent = text;
    container.appendChild(br);
    container.appendChild(link);
}

// Load saved grid setting
if (localStorage.getItem('grid-mode') === '4-col') {
    document.documentElement.style.setProperty('--grid-min-width', '280px');
    document.documentElement.style.setProperty('--view-source-margin', '80px');
}

// Load saved headings setting (default: hidden)
if (localStorage.getItem('headings-visible') !== 'true') {
    document.body.classList.add('hide-headings');
}

function toggleTheme() {
    document.body.classList.toggle('dark-grey-theme');
    // Sync theme across pages
    if (document.body.classList.contains('dark-grey-theme')) {
        localStorage.setItem('theme', 'dark-grey');
    } else {
        localStorage.removeItem('theme');
    }
}

function toggleHeadings() {
    document.body.classList.toggle('hide-headings');
    if (document.body.classList.contains('hide-headings')) {
        localStorage.removeItem('headings-visible');
    } else {
        localStorage.setItem('headings-visible', 'true');
    }
}

function toggleGrid() {
    const currentMode = localStorage.getItem('grid-mode');
    if (currentMode === '4-col') {
        document.documentElement.style.setProperty('--grid-min-width', '320px');
        document.documentElement.style.setProperty('--view-source-margin', '60px');
        localStorage.removeItem('grid-mode');
    } else {
        document.documentElement.style.setProperty('--grid-min-width', '280px');
        document.documentElement.style.setProperty('--view-source-margin', '80px');
        localStorage.setItem('grid-mode', '4-col');
    }
}

// Modal functionality
document.addEventListener('DOMContentLoaded', function() {
    const modal = document.getElementById('modal');
    const modalText = document.getElementById('modal-text');
    const header = document.getElementById('main-header');
    const footer = document.querySelector('footer');

    // Hero image animation: match repo list fade-in timing/style
    requestAnimationFrame(() => {
        document.body.classList.add('hero-animate');
    });

    // Fetch latest release from GitHub data
    const releaseLink = document.getElementById('latest-release-link');
    const repoList = document.getElementById('repo-list');

    if (releaseLink || repoList) {
        fetch(GITHUB_DATA_URL)
            .then(response => {
                if (!response.ok) {
                    throw new Error(`HTTP error! status: ${response.status}`);
                }
                return response.json();
            })
            .then(data => {
                if (releaseLink && data.latest_release) {
                    const safeReleaseUrl = safeUrl(data.latest_release.html_url);
                    if (safeReleaseUrl) {
                        releaseLink.href = safeReleaseUrl;
                        releaseLink.textContent = data.latest_release.tag_name.replace('v', '');
                        releaseLink.classList.add('kernel-link');
                    }
                }
                if (repoList && data.repos) {
                    const STAGGER_DELAY_SECONDS = 0.05;
                    if (!Array.isArray(data.repos) || data.repos.length === 0) {
                        throw new Error('No repos found');
                    }
                    repoList.innerHTML = '';
                    repoList.classList.add('repo-list-loaded');
                    data.repos.forEach((repo, index) => {
                        const li = document.createElement('li');
                        li.style.animationDelay = `${index * STAGGER_DELAY_SECONDS}s`;

                        const rank = document.createElement('span');
                        rank.className = 'repo-rank';
                        rank.textContent = String(index + 1);

                        const nameWrap = document.createElement('div');
                        nameWrap.className = 'repo-name-wrap';

                        const link = document.createElement('a');
                        link.href = safeUrl(repo.html_url) || 'https://github.com/harpertoken';
                        link.textContent = repo.name;
                        link.className = 'kernel-link repo-name';
                        link.dataset.modalText = `${repo.language || 'Unknown stack'} repository`;
                        nameWrap.appendChild(link);

                        const subline = document.createElement('span');
                        subline.className = 'repo-subline';
                        subline.textContent = repo.forks_count > 0
                            ? `${repo.forks_count} forks`
                            : 'Repository';
                        nameWrap.appendChild(subline);

                        const language = document.createElement('span');
                        language.className = 'repo-lang';
                        language.textContent = repo.language || 'n/a';

                        const stars = document.createElement('span');
                        stars.className = 'repo-stars';
                        stars.textContent = String(repo.stargazers_count || 0);

                        li.appendChild(rank);
                        li.appendChild(nameWrap);
                        li.appendChild(language);
                        li.appendChild(stars);

                        repoList.appendChild(li);
                    });
                }
            })
            .catch(err => {
                console.error('Error fetching GitHub data:', err);
                if (releaseLink) releaseLink.textContent = 'Error loading';
                if (repoList) {
                    repoList.innerHTML = '<li><span class="repo-rank">1</span><div class="repo-name-wrap"><a href="https://github.com/harpertoken" class="repo-name">harpertoken</a><span class="repo-subline">Data unavailable</span></div><span class="repo-lang">n/a</span><span class="repo-stars">0</span></li>';
                    repoList.classList.add('repo-list-loaded');
                }
            });
    }

    document.querySelectorAll('.team-member').forEach(member => {
        member.addEventListener('click', function(event) {
            event.preventDefault();
            const href = safeUrl(this.href) || '#';
            modalText.textContent = this.dataset.modalText || '';
            buildModalLink(modalText, href, 'Go');
            modal.style.display = 'block';
        });
    });

    document.addEventListener('click', function(event) {
        if (event.target.classList.contains('kernel-link')) {
            const href = event.target.href;
            const safeHref = safeUrl(href);
            const isExternal = safeHref && new URL(href, window.location.href).origin !== window.location.origin;

            if (!isExternal) {
                return;
            }

            event.preventDefault();
            modalText.textContent = event.target.dataset.modalText || '';
            buildModalLink(modalText, safeHref);
            modal.style.display = 'block';
        }
    });

    document.getElementById('legal-btn')?.addEventListener('click', function() {
        document.getElementById('modal-text').innerHTML = document.getElementById('legal-content').innerHTML;
        modal.style.display = 'block';
    });

    // Event delegation for modal buttons
    modal.addEventListener('click', function(e) {
        if (e.target.classList.contains('dotfiles-btn')) {
            document.getElementById('modal-text').textContent = e.target.dataset.modalText;
            modal.style.display = 'block';
            return;
        }
        if (e.target.id === 'modal-contrast-btn') {
            toggleTheme();
        } else if (e.target.id === 'grid-toggle-btn') {
            toggleGrid();
        } else if (e.target.id === 'headings-toggle-btn') {
            toggleHeadings();
        }
    });

    // Keyboard shortcuts for modal and theme
    document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') {
            e.preventDefault();
            modal.style.display = 'none';
        } else if (e.key === 'c' || e.key === 'C') {
            toggleTheme();
        }
    });

    document.querySelector('#modal .close').addEventListener('click', function() {
        modal.style.display = 'none';
    });

    window.addEventListener('scroll', function() {
        header?.classList.toggle('scrolled', window.scrollY > 10);
        footer.classList.toggle('scrolled', window.scrollY > 10);
    });

    window.addEventListener('click', function(event) {
        if (event.target == modal) {
            modal.style.display = 'none';
        }
    });
});
